975: 	private dispatchEvent(event: Proto.Event) {
976: 		switch (event.event) {
977: 			case EventName.syntaxDiag:
978: 			case EventName.semanticDiag:
979: 			case EventName.suggestionDiag:
980: 			case EventName.regionSemanticDiag: {
