982: 				this.loadingIndicator.reset();
983: 
984: 				const diagnosticEvent = event as Proto.DiagnosticEvent;
985: 				if (diagnosticEvent.body?.diagnostics) {
986: 					this._onDiagnosticsReceived.fire({
987: 						kind: getDiagnosticsKind(event),
988: 						resource: this.toResource(diagnosticEvent.body.file),
989: 						diagnostics: diagnosticEvent.body.diagnostics,
990: 						spans: diagnosticEvent.body.spans,
991: 					});
