// Watch for file changes on disk (e.g., from git operations) to refresh stale diagnostics
const fileWatcher = this._register(vscode.workspace.createFileSystemWatcher('**/*.{ts,tsx,js,jsx,mts,mjs,cts,cjs}', false, false, true));
fileWatcher.onDidChange(resource => {
	// Only refresh diagnostics for files that are not currently open in the editor
	if (!this.bufferSyncSupport.handles(resource)) {
		this.bufferSyncSupport.getErr([resource]);
	}
